// Supports two payload shapes:
// 1. Full VNTANA webhook: { product, organization, client }
// 2. Manual trigger:      { productUuid, clientUuid, orgSlug?, clientSlug? }
const body = $input.first().json.body ?? $input.first().json;

let productUuid, clientUuid, orgUuid, orgSlug, clientSlug, productName;

if (body.product) {
  productUuid  = body.product.uuid;
  productName  = body.product.name ?? '';
  orgUuid      = body.organization?.uuid ?? '49a01b09-ee65-4fc5-8777-433d7b5b5b29';
  orgSlug      = body.organization?.slug ?? 'DCicero';
  clientUuid   = body.client?.uuid ?? 'b577b1c8-80bd-4dab-b1b1-b22f9de4671a';
  clientSlug   = body.client?.slug ?? 'n8n-work';
} else {
  productUuid  = body.productUuid;
  clientUuid   = body.clientUuid   ?? 'b577b1c8-80bd-4dab-b1b1-b22f9de4671a';
  orgUuid      = body.orgUuid      ?? '49a01b09-ee65-4fc5-8777-433d7b5b5b29';
  orgSlug      = body.orgSlug      ?? 'DCicero';
  clientSlug   = body.clientSlug   ?? 'n8n-work';
  productName  = body.productName  ?? '';
}

if (!productUuid) throw new Error('productUuid is required');

return [{ json: { productUuid, clientUuid, orgUuid, orgSlug, clientSlug, productName } }];

const binaryData = $input.first().binary?.glbData;
if (!binaryData) throw new Error('No GLB binary data in glbData field');

const buf = Buffer.from(binaryData.data, 'base64');

const magic = buf.readUInt32LE(0);
if (magic !== 0x46546C67) throw new Error(`Not a valid GLB file (magic: 0x${magic.toString(16)})`);

const jsonChunkLength = buf.readUInt32LE(12);
const jsonChunkType   = buf.readUInt32LE(16);
if (jsonChunkType !== 0x4E4F534A) throw new Error('First GLB chunk is not JSON');

const jsonStr = buf.slice(20, 20 + jsonChunkLength).toString('utf8').replace(/\0+$/, '');
const gltf = JSON.parse(jsonStr);

const nodes  = gltf.nodes  ?? [];
const meshes = gltf.meshes ?? [];

const parentOf = new Array(nodes.length).fill(-1);
nodes.forEach((node, i) => {
  (node.children ?? []).forEach(ci => { parentOf[ci] = i; });
});

function findNamedAncestor(idx) {
  let cur = parentOf[idx];
  while (cur !== -1) {
    const name = (nodes[cur]?.name ?? '').trim();
    if (name && name.toUpperCase() !== 'NONE') return name;
    cur = parentOf[cur];
  }
  return null;
}

const meshNodes = [];
nodes.forEach((node, i) => {
  if (node.mesh === undefined) return;
  const rawName       = (node.name ?? '').trim();
  const meshName      = meshes[node.mesh]?.name ?? '';
  const namedAncestor = findNamedAncestor(i);
  const isNone        = !rawName || rawName.toUpperCase() === 'NONE';
  meshNodes.push({
    nodeIndex:     i,
    meshIndex:     node.mesh,
    rawName:       rawName || 'NONE',
    meshName,
    suggestedName: isNone ? (namedAncestor ?? '') : rawName,
    namedAncestor: namedAncestor ?? '',
    needsRename:   isNone
  });
});

const ids = $node['Extract IDs'].json;
return [{ json: {
  productUuid:  ids.productUuid,
  productName:  ids.productName || ids.productUuid,
  clientUuid:   ids.clientUuid,
  orgSlug:      ids.orgSlug,
  clientSlug:   ids.clientSlug,
  totalNodes:   nodes.length,
  totalMeshes:  meshNodes.length,
  needsRename:  meshNodes.filter(m => m.needsRename).length,
  meshNodes
} }];

const tree = $input.first().json;

const mapping = {
  productUuid:   tree.productUuid,
  productName:   tree.productName,
  clientUuid:    tree.clientUuid,
  extractedAt:   new Date().toISOString(),
  totalNodes:    tree.totalNodes,
  totalMeshes:   tree.totalMeshes,
  needsRename:   tree.needsRename,
  entries: tree.meshNodes.map(m => ({
    nodeIndex:     m.nodeIndex,
    meshIndex:     m.meshIndex,
    rawName:       m.rawName,
    meshName:      m.meshName,
    suggestedName: m.suggestedName,
    confirmedName: m.suggestedName,
    namedAncestor: m.namedAncestor,
    needsRename:   m.needsRename,
    isNew:         false
  }))
};

const jsonStr  = JSON.stringify(mapping, null, 2);
const fileName = `scene-mapping-${tree.productUuid}.json`;

const binary = {
  mappingFile: await this.helpers.prepareBinaryData(
    Buffer.from(jsonStr, 'utf8'),
    fileName,
    'application/json'
  )
};

return [{ json: { mapping, jsonStr, fileName, productUuid: tree.productUuid, clientUuid: tree.clientUuid, productName: tree.productName, orgSlug: tree.orgSlug, clientSlug: tree.clientSlug, totalMeshes: tree.totalMeshes, needsRename: tree.needsRename }, binary }];

const prev = $node['Build Mapping JSON'].json;
const mapperUrl = `https://vntana-store-production.up.railway.app/admin/parts-mapper.html?uuid=${prev.productUuid}&clientUuid=${prev.clientUuid}`;

const lines = [
  `*Parts Mapper ready: ${prev.productName}*`,
  `${prev.needsRename} of ${prev.totalMeshes} mesh nodes need renaming.`,
  '',
  `<${mapperUrl}|Open Parts Mapper>`
];

return [{ json: { mapperUrl, slackText: lines.join('\n'), ...prev } }];
